import json
from dataclasses import dataclass


@dataclass(frozen=True)
class Config:
    title: str = "Report"
    output_format: str = "text"
    max_rows: int = 10
    include_summary: bool = True


KNOWN_KEYS = {"title", "output_format", "max_rows", "include_summary"}


def load_config(path):
    """Load config from a JSON file, filling in defaults for missing keys."""
    with open(path) as f:
        raw = json.load(f)

    unknown_keys = set(raw.keys()) - KNOWN_KEYS
    if unknown_keys:
        raise ValueError(f"Unknown config key: {unknown_keys.pop()}")

    return Config(**{k: v for k, v in raw.items() if k in KNOWN_KEYS})

